   328→enum pass_positioning_ops
   329→{
   330→  PASS_POS_INSERT_AFTER,  /* Insert after the reference pass.  */
   331→  PASS_POS_INSERT_BEFORE, /* Insert before the reference pass.  */
   332→  PASS_POS_REPLACE        /* Replace the reference pass.  */
